'use client';

import React, { useState } from 'react';
import Image from 'next/image';
import { motion } from 'framer-motion';
import { fadeInUp, staggerContainer } from './animation-variants';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';

interface FreshDeliveryProps {
  adminData?: {
    title?: string;
    subtitle?: string;
    features?: string[];
    image?: string;
    deliverablePincodes?: string[];
    serviceable_pincodes?: string[];
  };
}

const FreshDeliverySection: React.FC<FreshDeliveryProps> = ({ adminData }) => {
  const [pincode, setPincode] = useState('');
  const [deliveryStatus, setDeliveryStatus] = useState<'idle' | 'checking' | 'available' | 'unavailable'>('idle');
  
  // Default data
  const defaultData = {
    title: 'Fresh Delivery, From Ocean to Table',
    subtitle: "We believe that the freshest seafood makes for the most delicious meals. That's why we've built a lightning-fast supply chain that brings seafood from the ocean to your table in record time.",
    features: [
      'Same-Day Delivery',
      'Temperature-Controlled Packaging',
      'Freshness Guarantee'
    ],
    image: '/images/fresh-delivery.jpg',
    deliverablePincodes: ['600001', '600002', '600003', '600004', '600005', '600006', '600010', '600018', '600020', '600025', '600034', '600040']
  };

  // Get values from admin data or use defaults
  const title = adminData?.title || defaultData.title;
  const subtitle = adminData?.subtitle || defaultData.subtitle;
  const features = adminData?.features || defaultData.features;
  const image = adminData?.image || defaultData.image;
  
  // Use serviceable_pincodes from admin panel if available, fallback to deliverablePincodes, then to defaults
  const deliverablePincodes = adminData?.serviceable_pincodes || adminData?.deliverablePincodes || defaultData.deliverablePincodes;
  
  // Check delivery availability
  const checkDeliveryAvailability = () => {
    if (!pincode || pincode.length !== 6 || !/^\d+$/.test(pincode)) {
      toast.error("Please enter a valid 6-digit pincode");
      return;
    }
    
    setDeliveryStatus('checking');
    
    // Simulate API check with timeout
    setTimeout(() => {
      if (deliverablePincodes.includes(pincode)) {
        setDeliveryStatus('available');
        toast.success("Great news! We deliver to your area.");
      } else {
        setDeliveryStatus('unavailable');
        toast.error("Sorry, we don't deliver to your area yet.");
      }
    }, 1000);
  };

  return (
    <section className="py-6 sm:py-8 lg:py-12 fresh-delivery-section">
      <div className="container mx-auto px-4 sm:px-6 lg:px-8">
        <motion.div 
          className="flex flex-col lg:flex-row items-center gap-8 sm:gap-10 lg:gap-12"
          initial="visible" // Start with visible state
          animate="visible"
          variants={staggerContainer}
        >
          <motion.div 
            className="lg:w-1/2 relative h-64 sm:h-80 lg:h-96 w-full"
            variants={fadeInUp}
          >
            <div className="bg-gray-200 absolute inset-0 rounded-lg flex items-center justify-center">
              {image ? (
                <Image 
                  src={image} 
                  alt="Fresh seafood delivery" 
                  fill
                  className="object-cover rounded-lg"
                />
              ) : (
                <span className="text-gray-400 text-sm sm:text-base">Delivery Image</span>
              )}
            </div>
          </motion.div>
          
          <motion.div 
            className="lg:w-1/2"
            variants={fadeInUp}
          >
            <h2 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-[#e57373] mb-4 sm:mb-6">{title}</h2>
            <p className="text-gray-700 mb-6 sm:mb-8 text-sm sm:text-base leading-relaxed">
              {subtitle}
            </p>
            
            <motion.div 
              className="space-y-4 sm:space-y-6"
              variants={staggerContainer}
            >
              {features.map((feature, index) => (
                <motion.div 
                  key={index} 
                  className="flex items-center"
                  variants={fadeInUp}
                >
                  <div className="bg-red-100 p-2 sm:p-3 rounded-full mr-3 sm:mr-4 flex-shrink-0">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 sm:h-6 sm:w-6 text-[#e57373]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
                    </svg>
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-800 text-base sm:text-lg mb-1">{feature}</h3>
                    <p className="text-gray-600 text-sm sm:text-base leading-relaxed">
                      {index === 0 && "Order before 2 PM for same-day delivery in select areas."}
                      {index === 1 && "Our specialized packaging keeps seafood at the optimal temperature."}
                      {index === 2 && "If you're not 100% satisfied with the freshness, we'll refund you."}
                    </p>
                  </div>
                </motion.div>
              ))}
            </motion.div>
            
            <motion.div 
              className="mt-6 sm:mt-8 check-delivery"
              variants={fadeInUp}
            >
              <div className="space-y-4">
                <h3 className="font-semibold text-gray-800 text-lg">Check Delivery in Your Area</h3>
                
                <div className="pincode-input-container">
                  <Input
                    type="text"
                    placeholder="Enter pincode (e.g., 600034)"
                    value={pincode}
                    onChange={(e) => setPincode(e.target.value)}
                    className="pincode-input"
                    maxLength={6}
                  />
                  
                  <Button
                    onClick={checkDeliveryAvailability}
                    className="check-button"
                    disabled={deliveryStatus === 'checking'}
                  >
                    {deliveryStatus === 'checking' ? 'Checking...' : 'Check Availability'}
                  </Button>
                </div>
                
                {deliveryStatus === 'available' && (
                  <div className="delivery-status status-success">
                    <p className="font-medium">Your area is deliverable! 🎉</p>
                    <p className="text-sm">We deliver to your location. Order now for fresh seafood delivered to your doorstep.</p>
                  </div>
                )}
                
                {deliveryStatus === 'unavailable' && (
                  <div className="delivery-status status-error">
                    <p className="font-medium">Currently not delivering to your location</p>
                    <p className="text-sm">We're expanding our delivery network. Please check back later.</p>
                  </div>
                )}
              </div>
            </motion.div>
          </motion.div>
        </motion.div>
      </div>
    </section>
  );
};

export default FreshDeliverySection;
