"use client";

import { useState, useEffect, useRef } from "react";
import Image from "next/image";
import { Button } from "@/components/ui/button";
import { motion } from "framer-motion";

// Add Google Fonts via CSS import
const googleFontsStyle = {
  fontFamily: "'Italianno', cursive"
};

const HeroBanner = () => {
  // Refs for animation targets
  const containerRef = useRef<HTMLDivElement>(null);
  const welcomeTextRef = useRef<HTMLHeadingElement>(null);
  const mainTitleRef = useRef<HTMLHeadingElement>(null);
  const signatureTextRef = useRef<HTMLSpanElement>(null);
  const signaturePathRef = useRef<SVGPathElement>(null);
  const descriptionRef = useRef<HTMLParagraphElement>(null);
  const promisePathRef = useRef<SVGPathElement>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);
  
  const [imageLoaded, setImageLoaded] = useState(false);
  const [isMobile, setIsMobile] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  
  // Check for mobile view
  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth <= 640);
    };
    
    checkMobile();
    window.addEventListener('resize', checkMobile);
    
    return () => {
      window.removeEventListener('resize', checkMobile);
    };
  }, []);
  
  // Handle scroll events with throttling to prevent performance issues
  useEffect(() => {
    const handleScroll = () => {
      setScrollY(window.scrollY);
    };
    
    // Add scroll listener with passive option for better performance
    window.addEventListener('scroll', handleScroll, { passive: true });
    
    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);
  
  // Handle image load event
  const handleImageLoad = () => {
    setImageLoaded(true);
  };

  // Calculate opacity based on scroll position, ensuring it never fully disappears
  const calculateOpacity = () => {
    // Ensure the banner stays at least 20% visible
    return Math.max(1 - (scrollY / 500), 0.2);
  };
  
  // Calculate image parallax effect - subtle movement as user scrolls
  const calculateImageY = () => {
    return scrollY * 0.2; // Subtle parallax effect
  };

  return (
    <div className="relative w-full hero-banner-container" ref={containerRef}>
      <motion.div 
        className="relative w-full h-[400px] sm:h-[450px] md:h-[550px] lg:h-[600px] overflow-hidden"
        initial={{ opacity: 0.9 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.5 }}
      >
        {/* Background image with fixed position to ensure it doesn't disappear */}
        <div 
          style={{ 
            transform: `translateY(${calculateImageY()}px)`,
            position: 'absolute', 
            width: '100%', 
            height: '100%' 
          }}
        >
          <Image
            src="/images/bg.jpg"
            alt="Kadal Thunai Fresh Seafood"
            fill
            className="object-cover object-center"
            priority
            onLoad={handleImageLoad}
            sizes="100vw"
          />
        </div>
        
        {/* Overlay with controlled opacity */}
        <div 
          className="absolute inset-0 bg-black bg-opacity-55 sm:bg-opacity-45 md:bg-opacity-40 flex items-center justify-center sm:justify-start sm:items-start sm:pt-12 md:pt-16 lg:pt-20 hero-banner-text"
          style={{ 
            opacity: calculateOpacity(),
            // Important: make sure this element is always visible
            visibility: 'visible' 
          }}
        >
          <div className="container mx-auto px-4 sm:px-6 lg:px-8">
            <div className="max-w-2xl lg:max-w-3xl text-white text-center sm:text-left">
              <div className="mb-6 sm:mb-8 lg:mb-10">
                <h1 
                  ref={welcomeTextRef}
                  className="text-lg sm:text-xl md:text-2xl lg:text-4xl font-bold leading-tight mb-2 sm:mb-3 lg:mb-4"
                  data-component-name="HeroBanner"
                >
                  Welcome To,
                </h1>
                <h1 
                  ref={mainTitleRef}
                  className="text-2xl sm:text-3xl md:text-4xl lg:text-6xl font-bold leading-tight text-red-600 mb-3 sm:mb-4 lg:mb-6"
                  data-component-name="HeroBanner"
                >
                  Kadal Thunai.
                </h1>
                <div className="relative inline-block mt-2 sm:mt-3 lg:mt-4">
                  <span
                    ref={signatureTextRef}
                    style={googleFontsStyle}
                    className="relative z-10 text-xl sm:text-2xl md:text-3xl lg:text-4xl text-white"
                    data-component-name="HeroBanner"
                  >
                    SignatureCuts
                  </span>
                  <div className="relative w-full mt-1 sm:mt-2">
                    <svg 
                      className="w-full h-3 sm:h-4 lg:h-5" 
                      viewBox="0 0 300 25" 
                      preserveAspectRatio="none"
                      data-component-name="HeroBanner"
                    >
                      <path 
                        ref={signaturePathRef}
                        d="M0,18 C30,8 70,28 120,13 C170,-2 210,18 260,8 C310,-2 350,18 400,13" 
                        fill="none" 
                        className="text-red-600" 
                        stroke="currentColor" 
                        strokeWidth="3"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        vectorEffect="non-scaling-stroke"
                        data-component-name="HeroBanner"
                      />
                    </svg>
                  </div>
                </div>
                <p 
                  ref={descriptionRef}
                  className="text-sm sm:text-base md:text-lg lg:text-xl mt-3 sm:mt-4 lg:mt-8 text-white font-medium leading-relaxed max-w-lg mx-auto sm:mx-0"
                >
                  No matter what we always serves fresh. 
                  <span className="relative ml-1">
                    <span className="relative z-10 font-bold">Promise!!</span>
                    <svg 
                      className="absolute -bottom-2 sm:-bottom-2.5 left-0 w-full h-2.5 sm:h-3 md:h-4" 
                      viewBox="0 0 100 25" 
                      preserveAspectRatio="none"
                      data-component-name="HeroBanner"
                    >
                      <path 
                        ref={promisePathRef}
                        d="M0,18 C15,8 35,28 50,13 C65,-2 85,18 100,8" 
                        fill="none" 
                        className="text-red-600" 
                        stroke="currentColor" 
                        strokeWidth="2.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        vectorEffect="non-scaling-stroke"
                        data-component-name="HeroBanner"
                      />
                    </svg>
                  </span>
                </p>
              </div>
              <div data-component-name="MotionComponent" className="mt-6 sm:mt-8 lg:mt-10">
                <Button 
                  ref={buttonRef}
                  className="bg-red-600 hover:bg-red-700 text-xs sm:text-sm md:text-base px-4 sm:px-6 md:px-8 py-2 sm:py-3 md:py-4 lg:py-6 transition-all duration-300 hover:scale-105 shadow-lg hover:shadow-xl"
                  data-component-name="_c"
                >
                  SHOP NOW
                </Button>
              </div>
            </div>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

export default HeroBanner;
