// Avatar Image component
interface AvatarImageProps {
  src: string;
  alt: string;
  className?: string;
}

const AvatarImage = ({ src, alt, className = "" }: AvatarImageProps) => {
  const [error, setError] = useState(false);
  
  return (
    <div className={`w-full h-full rounded-full overflow-hidden ${className}`}>
      {!error ? (
        <Image 
          src={src} 
          alt={alt}
          width={56}
          height={56}
          className="object-cover h-full w-full"
          loading="lazy"
          onError={() => setError(true)}
        />
      ) : (
        <div className="w-full h-full bg-red-100 flex items-center justify-center text-red-500">
          <span className="text-xl font-semibold">{alt.charAt(0)}</span>
        </div>
      )}
    </div>
  );
};

